const jwt = require('jsonwebtoken');

const authenticate = (req, res, next) => {
  const token = req.headers['authorization'];
  const decoded = jwt.verify(token, process.env.JWT_SECRET, (err, decoded) => { if (err) { return res.status(401).json({ error: 'Invalid token' }); } return decoded; });
  req.user = decoded;
  next();
};

module.exports = authenticate;

